class Playground {

    async run(inputs) {
        const n = parseInt(inputs[0]);

        if (isNaN(n) || n < 0) {
            this.log("Input 'n' must be a non-negative integer.");
            return -1;
        }

        this.callstack.init();
        this.recursionTree.init();

        this.log(`Starting factorial calculation for n = ${n}`);
        await this.await();

        const result = await this.calculateFactorial(n);

        this.log(`Final result: ${n}! = ${result}`);
        return result;
    }

    async calculateFactorial(currentN) {
        // Push a new frame onto the call stack for the current function call
        this.callstack.pushFrame('factorial', { n: currentN });
        // Enter a new node in the recursion tree
        this.recursionTree.enterNode(currentN, `factorial(${currentN})`);
        this.log(`Entering factorial(${currentN})`);
        await this.await();

        // Base Case: factorial of 0 or 1 is 1
        if (currentN === 0 || currentN === 1) {
            this.log(`Base case reached: factorial(${currentN}) is 1.`);
            this.callstack.updateLocal('result', 1);
            await this.await();

            // Pop the frame and exit the recursion tree node with the result
            this.callstack.popFrame(1);
            this.recursionTree.exitNode('green'); // Mark as successfully computed
            return 1;
        }

        // Recursive Step: n * factorial(n-1)
        this.log(`Calculating factorial(${currentN}) = ${currentN} * factorial(${currentN - 1})`);
        this.callstack.updateLocal('n', currentN);
        await this.await();

        // Recursively call for n-1
        const subProblemResult = await this.calculateFactorial(currentN - 1);

        this.log(`Received result for factorial(${currentN - 1}): ${subProblemResult}`);
        this.callstack.updateLocal('subProblemResult', subProblemResult);
        await this.await();

        const currentResult = currentN * subProblemResult;
        this.log(`Current result for factorial(${currentN}): ${currentN} * ${subProblemResult} = ${currentResult}`);
        this.callstack.updateLocal('result', currentResult);
        await this.await();

        // Pop the frame and exit the recursion tree node with the result
        this.callstack.popFrame(currentResult);
        this.recursionTree.exitNode('green'); // Mark as successfully computed
        return currentResult;
    }
}
